def render_card(row):
    carrier = detect_carrier(row["Airlines"])
    meta    = AIRLINE_META.get(carrier, {})
    card_cls   = meta.get("class", "")
    logo_uri   = meta.get("logo", "")
    airline_str = row["Airlines"]
    if len(airline_str) > 45:
        airline_str = airline_str[:45] + "…"
    region_cls = "tag-region-ksa" if "Saudi" in row["Region"] else                  ("tag-region-me" if "Middle" in row["Region"] else "tag-region-glob")
    type_cls = "tag-ops" if "Operations" in row["Type"] else "tag-comm"

    # Logo html
    logo_html = f'''<img src="{logo_uri}" class="airline-logo-strip" alt="airline logo">''' if logo_uri else ""

    # Time display
    try:
        pub_dt = row.get("PublishedDT")
        if pub_dt is None or (isinstance(pub_dt, float)):
            pub_dt = datetime.strptime(row["Published"], "%Y-%m-%d")
        now = datetime.now()
        diff_h = int((now - pub_dt).total_seconds() / 3600)
        if diff_h <= 0:   time_str = "Just now"
        elif diff_h < 24: time_str = f"{diff_h}h ago"
        else:             time_str = f"{diff_h // 24}d ago"
    except:
        time_str = row["Published"]

    summary_short = row["Summary"][:200] + ("…" if len(row["Summary"]) > 200 else "")

    st.markdown(f"""
    <div class="news-card {card_cls}">
      {logo_html}
      <div class="news-card-title">{row["Title"]}</div>
      <div class="news-card-summary">{summary_short}</div>
      <div class="news-card-meta">
        <span class="tag {region_cls}">{row["Region"]}</span>
        <span class="tag {type_cls}">{row["Type"]}</span>
        <span class="tag tag-airline">✈ {airline_str}</span>
        <span class="tag tag-time">🕐 {time_str}</span>
      </div>
      <a class="news-card-link" href="{row["Link"]}" target="_blank">View full report →</a>
    </div>
    """, unsafe_allow_html=True)

# ============================================================
# 11. RENDER FEED
# ============================================================
st.markdown('<div class="section-header"><span class="dot" style="background:#00B4B4"></span>Filtered News Feed &amp; Operational Intel</div>', unsafe_allow_html=True)

if "Local Airlines 🇸🇦" in selected_cat and not df_local.empty:
    st.markdown('<span class="category-header cat-local">🇸🇦 Local Airlines</span>', unsafe_allow_html=True)
    for _, row in df_local.iterrows():
        render_card(row)

if "International ✈️" in selected_cat and not df_intl.empty:
    st.markdown('<span class="category-header cat-intl">✈️ International Airlines</span>', unsafe_allow_html=True)
    for _, row in df_intl.iterrows():
        render_card(row)

if df_filtered.empty:
    st.markdown('<div style="background:#161B22;border:1px solid #21262D;border-radius:10px;padding:2rem;text-align:center;color:#6E7681;">No reports match the current filters.</div>', unsafe_allow_html=True)
